import React from 'react';
import Typewriter from 'components/Typewriter';
import Scrollchor from 'react-scrollchor';

class Hero extends React.PureComponent {
  constructor(props) {
    super(props);
  }

  render() {
    return (
      <div className="hero-container">
        <Typewriter className="hero-title" text="Ayush Bairagi" />
        <div className="hero-description">
            A <strike>self-taught</strike> "community-taught" programmer with a "can-do" attitude who developed his interest in Computer Science and Software Development over the years. Enjoy taking challenges and <i class="blue lighten-4">developing beautiful, functional, responsive and easy-to-use products.</i> <br></br>The best place to find Ayush is in front of his system. When he is not getting his hands dirty with code, he likes to hang around with like-minded people to share his knowledge and learn more.
        </div>
      </div>
    );
  }
}

export default Hero;



